#include <stdio.h>
#define DEBUG 0
#if DEBUG
  #include <assert.h>
#endif

//0.130s

typedef long long ll;

ll min(ll x, ll y) {
  return x < y ? x : y;
}

void swap(ll *xp, ll *yp) {
  ll h = *xp;
  *xp = *yp;
  *yp = h;
}

ll lessEqualInTable(int n, int m, ll x) {
  ll result = 0;
  ll rightmostFullColumn = min(x, x/m);
  result += rightmostFullColumn * min(x, m);
  ll rightmostColumn = min(x, n);
  ll rightmostMoreThanOneColumn = min(x / 2, n);
  result += (rightmostColumn - rightmostMoreThanOneColumn);
  for (ll column = rightmostFullColumn + 1; column <= rightmostMoreThanOneColumn; column++)
    result += x / column;
  return result;
}

ll findKthInList(ll n, ll m, ll k) {
  if (n > m)
    swap(&n, &m);
  if (k == 1)
    return 1;
  ll l = 1, r = n*m, mid;
  while (r - l > 1) {
    mid = (l + r) / 2;
    if (lessEqualInTable(n, m, mid) >= k)
      r = mid;
    else
      l = mid;
  }
  return l + 1;
}

#if DEBUG
void assertions() {
  assert(findKthInList(10, 10, 98) == 90);
  assert(findKthInList(10, 10, 97) == 81);
  assert(findKthInList(4, 7, 4) == 3);
  assert(findKthInList(1, 1, 1) == 1);
  assert(findKthInList(100000, 100000, 10000000000) == 10000000000);
  assert(findKthInList(100000, 100000, 1) == 1);
  assert(findKthInList(100000, 100000, 2) == 2);
  assert(findKthInList(100000, 100000, 3) == 2);
  assert(findKthInList(100000, 100000, 4) == 3);
  assert(findKthInList(100000, 100000, 5) == 3);
  assert(findKthInList(1, 5, 2) == 2);
  assert(findKthInList(5, 1, 2) == 2);
  printf("assertions OK\n");
}
#endif

int main() {
  ll n, m, k;
  #if DEBUG
    assertions();
  #endif
  scanf("%lld %lld %lld", &n, &m, &k);
  printf("%lld\n", findKthInList(n, m, k));
  return 0;
}

